  ('social-worker-moex-00191', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某方案的目標是「提升親密關係受暴婦女的自我權能」，內容是為受暴婦女辦理支持團體、心理劇 課程、藝術創作社團等，年度報告裡呈現了各場次人數和時數，以及參與者活動前、後的自我權 能量表檢測的變化，還有創作公開展演的新聞報導數量及網頁觸及人數。上述方案評估涉及的類', '["產出", "成效", "成本效益", "滿意度  ⑤服務品質  ⑥社會影響力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
