  ('social-worker-moex-00197', 'social-worker', 'social-worker-moex-114-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關危機對於社會服務機構可能造成的影響，下列敘述何者錯誤？', '["危機若未妥善處理，將嚴重影響組織的聲譽或形象", "危機的發生可能衝擊到組織的價值或目標，而與政府部門或公共組織間產生衝突或難以整合", "危機出現的時機、地點難以事前預測，故難以精確進行決策", "處理危機的過程中往往涉及太多利害關係人，致使組織能量難以負荷，故須以維繫組織生存為 前提"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:01+00:00", "source_pdf_sha1": "6c7bbd6c0843", "answer_pdf_sha1": "3cc1800551f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
